class TimeToLiveCache:
    def __init__(self, default_ttl_seconds=60):
        self._cache = {}
        self._ttl = default_ttl_seconds
    def get(self, key):
        if key not in self._cache:
            return None
        value, timestamp = self._cache[key]
        if time.time() - timestamp > self._ttl:
            del self._cache[key]
            return None
        return value
